import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BYYsWsaA.js";const m=JSON.parse('{"title":"Collaborate with Your Team","description":"","frontmatter":{},"headers":[],"relativePath":"guide/collaboration.md","filePath":"guide/collaboration.md"}'),s={name:"guide/collaboration.md"};function l(i,e,n,h,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="collaborate-with-your-team" tabindex="-1">Collaborate with Your Team <a class="header-anchor" href="#collaborate-with-your-team" aria-label="Permalink to &quot;Collaborate with Your Team&quot;">​</a></h1><p>Wafflebase lets multiple people edit the same spreadsheet at the same time. This guide shows you how to share a document and work together.</p><h2 id="share-a-document" tabindex="-1">Share a Document <a class="header-anchor" href="#share-a-document" aria-label="Permalink to &quot;Share a Document&quot;">​</a></h2><ol><li>Open the document you want to share</li><li>Click the <strong>Share</strong> button in the toolbar</li><li>Copy the generated link</li></ol><p>Send the link to your teammates. Anyone with the link can open the document.</p><h3 id="access-levels" tabindex="-1">Access Levels <a class="header-anchor" href="#access-levels" aria-label="Permalink to &quot;Access Levels&quot;">​</a></h3><p>When sharing, you can choose the access level:</p><ul><li><strong>View</strong> — Can see the data but not edit</li><li><strong>Edit</strong> — Can view and modify the data</li></ul><h2 id="edit-together" tabindex="-1">Edit Together <a class="header-anchor" href="#edit-together" aria-label="Permalink to &quot;Edit Together&quot;">​</a></h2><p>When a teammate opens your shared link, you&#39;ll see:</p><ul><li><strong>Their cursor</strong> — A colored highlight shows which cell they&#39;ve selected</li><li><strong>Their name</strong> — Appears near their cursor so you know who&#39;s editing where</li><li><strong>Live changes</strong> — When they type a value or formula, you see it appear instantly</li></ul><p>You don&#39;t need to refresh or save. Everything syncs automatically.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Each collaborator gets a unique color, so you can easily tell who is working where.</p></div><h2 id="how-conflicts-work" tabindex="-1">How Conflicts Work <a class="header-anchor" href="#how-conflicts-work" aria-label="Permalink to &quot;How Conflicts Work&quot;">​</a></h2><p>What happens if two people edit the <strong>same cell</strong> at the same time?</p><p>Wafflebase uses CRDTs (Conflict-free Replicated Data Types) to handle this. Both edits are preserved in the system — the last writer&#39;s value is displayed. There&#39;s no &quot;conflict dialog&quot; or manual merge step.</p><p>In practice, presence cursors make it easy to see where others are working, so simultaneous edits to the same cell are rare.</p><h2 id="tips-for-team-spreadsheets" tabindex="-1">Tips for Team Spreadsheets <a class="header-anchor" href="#tips-for-team-spreadsheets" aria-label="Permalink to &quot;Tips for Team Spreadsheets&quot;">​</a></h2><ul><li><strong>Use separate tabs</strong> — Give each team member their own tab for data entry, with a summary tab that pulls data using formulas</li><li><strong>Use clear headers</strong> — Label your columns so teammates know what goes where</li><li><strong>Communicate changes</strong> — If you restructure columns or rename tabs, let your team know</li></ul>',19)])])}const p=t(s,[["render",l]]);export{m as __pageData,p as default};
